// autoShadeDelta is the HCL blend fraction used to derive the darker/lighter endpoints
// for a single-stop (auto-shade) gradient, once the segment is wide enough to show the
// base color between them (autoShadeFullCells or more visible cells).
const autoShadeDelta = 0.15

// autoShadeFullCells is the cell count at which autoShade reaches its full delta. Below
// it, the interpolation in GradientCells has no room for the base color to render between
// the two endpoints (at 2 cells they sit directly adjacent), so the whole delta reads as
// one hard step; scaling it down by cells keeps narrow segments looking like a subtle
// sheen instead of a sharp two-tone split.
const autoShadeFullCells = 6

var (
	hclBlack = colorful.Color{R: 0, G: 0, B: 0}
	hclWhite = colorful.Color{R: 1, G: 1, B: 1}
)

// autoShade spreads a single resolved color into a darker-base-lighter blend in HCL
// space, giving a single-stop gradient the same darker/lighter/base endpoints
// GradientCells already knows how to interpolate across cells. cells must be >= 2.
func autoShade(base colorful.Color, cells int) []colorful.Color {
	delta := autoShadeDelta
	if cells < autoShadeFullCells {
		delta *= float64(cells) / float64(autoShadeFullCells)
	}

	darker := base.BlendHcl(hclBlack, delta).Clamped()
	lighter := base.BlendHcl(hclWhite, delta).Clamped()

	return []colorful.Color{darker, base, lighter}
}

