27	func (p Palette) resolveColor(colorName Ansi, depth int, originalColorName *Ansi) (Ansi, error) {
28		key, ok := asPaletteKey(colorName)
29		// colorName is not a palette key, return it as is
30		if !ok {
31			return colorName, nil
32		}
33	
34		color, ok := p[key]
35		if !ok {
36			return "", &PaletteKeyError{Key: key, palette: p}
37		}
38	
39		if strings.Contains(color.String(), "{{") {
40			rendered, err := template.RenderTrusted(color.String(), nil)
41			if err != nil {
42				return "", err
43			}
44	
45			color = Ansi(strings.TrimSpace(rendered))
46		}
47	
48		if _, isKey := isPaletteKey(color); isKey {
49			if depth > paletteMaxRecursionDepth {
50				return "", &PaletteRecursiveKeyError{Key: *originalColorName, Value: color, depth: depth}
51			}
52	
53			return p.resolveColor(color, depth+1, originalColorName)
54		}
55	
56		return color, nil
57	}
