func candidateShade(base colorful.Color, slope, floor, ceil float64) colorful.Color {
	h, c, l := base.Hcl()
	delta := math.Max(floor, math.Min(ceil, slope*l))
	l = math.Max(0.02, l-delta)
	shade := colorful.Hcl(h, c, l)
	for !shade.IsValid() && c > 0 {
		c -= 0.005
		shade = colorful.Hcl(h, c, l)
	}
