// autoShadeDeltaSlope/Floor/Ceiling shape the lightness shift autoShade applies, as a
// fraction of the base color's own headroom toward black or white (so a color already
// close to the target end still shifts visibly, and one far from it doesn't overshoot),
// clamped to a floor (a visible ramp even near the target end) and a ceiling (no harsh
// jump far from it). GradientLast has no cell count to work with (see its doc comment),
// so the total base-to-shade delta is fixed regardless of segment width; these values are
// tuned so a 2-3 cell segment - the common case dark-gradient/light-gradient exists for -
// lands its per-step jump close to a JND (~2.3 CIE76 ΔE) rather than a hard color swap.
const (
	autoShadeDeltaSlope   = 0.08
	autoShadeDeltaFloor   = 0.025
	autoShadeDeltaCeiling = 0.05
	autoShadeMinLightness = 0.02
	autoShadeMaxLightness = 0.98
	autoShadeChromaStep   = 0.005
)

// autoShade derives a dark-gradient/light-gradient's second stop: same hue, same chroma
// other than what the sRGB gamut forces away, lightness shifted toward black (shadeDark)
// or white (shadeLight) by a clamped fraction of the base's own headroom in that
// direction. Blending toward black/white directly (the previous approach) pulls chroma
// along with it, which reads as the color going muddy rather than deepening/brightening;
// walking chroma down only as far as IsValid demands keeps the hue exact and preserves as
// much saturation as the gamut allows at the new lightness. GradientLast mirrors this on
// the raw (unresolved) stop text so a segment's trailing separator/cap matches the color
// GradientCells renders the last cell as.
func autoShade(base colorful.Color, dir shadeDirection) colorful.Color {
	h, c, l := base.Hcl()

	if dir == shadeLight {
		delta := math.Max(autoShadeDeltaFloor, math.Min(autoShadeDeltaCeiling, autoShadeDeltaSlope*(1-l)))
		l = math.Min(autoShadeMaxLightness, l+delta)
	} else {
		delta := math.Max(autoShadeDeltaFloor, math.Min(autoShadeDeltaCeiling, autoShadeDeltaSlope*l))
		l = math.Max(autoShadeMinLightness, l-delta)
	}

	shade := colorful.Hcl(h, c, l)
	for !shade.IsValid() && c > 0 {
		c -= autoShadeChromaStep
		shade = colorful.Hcl(h, c, l)
	}

	return shade.Clamped()
}

