		expectedLast := GradientCells(Ansi("linear-gradient(#3465A4, "+gradient.GradientLast().String()+")"), 5, &Defaults{}, false, nil, nil)
		assert.Equal(t, expectedLast[len(expectedLast)-1], result[len(result)-1], tc.Case+": the last cell must match GradientLast, the color separators/caps use")

		assert.NotEqual(t, result[0], result[len(result)-1], tc.Case+": the segment must actually shade, not render solid")
	}
