// autoShadeStepSlope/Floor/Ceiling shape the PER-CELL-STEP lightness shift autoShade
// targets, as a fraction of the base color's own headroom toward black or white (so a
// color already close to the target end still shifts visibly, and one far from it
// doesn't overshoot), clamped to a floor (a visible ramp even near the target end) and a
// ceiling (no harsh per-step jump far from it) tuned to land close to a JND (~2.3 CIE76
// ΔE) per step. autoShadeDeltaMax caps the TOTAL base-to-shade delta a wide segment can
// reach, so an already-narrow-range color doesn't get crushed toward black/white.
const (
	autoShadeStepSlope    = 0.04
	autoShadeStepFloor    = 0.0125
	autoShadeStepCeiling  = 0.025
	autoShadeDeltaMax     = 0.35
	autoShadeMinLightness = 0.02
	autoShadeMaxLightness = 0.98
	autoShadeChromaStep   = 0.005
)

// autoShade derives a dark-gradient/light-gradient's second stop: same hue, same chroma
// other than what the sRGB gamut forces away, lightness shifted toward black (shadeDark)
// or white (shadeLight). The shift is a per-cell-step target (see autoShadeStepSlope)
// times steps = max(1, cells-1), so GradientCells(c, cells, ...) always lands its actual
// last cell here regardless of width: a 2-3 cell segment gets one gentle step, matching
// what narrow segments were tuned to look like, while a wide segment's larger total delta
// still reads as a clear gradient instead of fading into an imperceptibly fine ramp -
// capped at autoShadeDeltaMax so an extremely wide segment doesn't crush toward black or
// white. Blending toward black/white directly (an earlier approach) pulls chroma along
// with it, which reads as the color going muddy rather than deepening/brightening;
// walking chroma down only as far as IsValid demands keeps the hue exact and preserves as
// much saturation as the gamut allows at the new lightness. GradientLastForCells mirrors
// this on the raw (unresolved) stop text so a segment's trailing separator/cap matches
// the color GradientCells renders the last cell as, for the SAME cells.
func autoShade(base colorful.Color, dir shadeDirection, cells int) colorful.Color {
	h, c, l := base.Hcl()

	steps := max(1, cells-1)

	if dir == shadeLight {
		step := math.Max(autoShadeStepFloor, math.Min(autoShadeStepCeiling, autoShadeStepSlope*(1-l)))
		delta := math.Min(autoShadeDeltaMax, step*float64(steps))
		l = math.Min(autoShadeMaxLightness, l+delta)
	} else {
		step := math.Max(autoShadeStepFloor, math.Min(autoShadeStepCeiling, autoShadeStepSlope*l))
		delta := math.Min(autoShadeDeltaMax, step*float64(steps))
		l = math.Max(autoShadeMinLightness, l-delta)
	}

	shade := colorful.Hcl(h, c, l)
	for !shade.IsValid() && c > 0 {
		c -= autoShadeChromaStep
		shade = colorful.Hcl(h, c, l)
	}

